#!/bin/bash
set -e

# Run sqlc generate
sqlc generate

# Deduplicate db.go files between MySQL and SQLite
# Both use database/sql and generate identical code.
# This script post-processes to use a shared package for common types.

SQLITE_DB="internal/db/sqlite/db.go"

# Replace sqlite/db.go to use shared package for common types
cat > "$SQLITE_DB" << 'EOFILE'
//go:build sqlite

// Code generated by sqlc. DO NOT EDIT.
// versions:
//   sqlc v1.30.0
//
// This file uses the shared package for common types to avoid code duplication.

package sqlite

import (
	"github.com/LarsArtmann/template-sqlc/internal/db/shared"
)

// DBTX is imported from shared package
type DBTX = shared.DBTX

// Queries struct - embeds shared.BaseQueries for the db field
type Queries struct {
	*shared.BaseQueries
}

// New returns a new Queries instance
func New(db DBTX) *Queries {
	return &Queries{BaseQueries: shared.NewBase(db)}
}
EOFILE

echo "Code generation and deduplication complete"
